    @Override
    public String toString()
    {
        StringBuilder sb = new StringBuilder(rows()*cols());

        sb.append("[");

        for(int i = 0; i < rows(); i++)
        {
            sb.append(get(i, 0));
            for(int j = 1; j < cols(); j++)
            {
                sb.append(", ").append(get(i, j));
            }
            sb.append(";");
        }

        sb.append("]");
        return sb.toString();
